         tapa::ostream<float>& c, uint64_t n) {
#pragma HLS disaggregate variable = a
#pragma HLS interface ap_fifo port = a._
#pragma HLS aggregate variable = a._ bit
#pragma HLS interface ap_fifo port = a._peek
