void(b._peek.empty());

#pragma HLS disaggregate variable = c
#pragma HLS interface ap_fifo port = c._
#pragma HLS aggregate variable = c._ bit
void(c._.full());


  for (uint64_t i = 0; i < n; ++i) {
    c << (a.read() + b.read());
  }
